h; ?></section><section class="col-md-3 panel"><h6>Reparaciones al salir</h6><?php foreach(['rep_sal_mufas_termo'=>'Mufas Termocontraible','rep_sal_mufa_union'=>'Mufa de unión','rep_sal_chaquetas'=>'Chaquetas'] as $n=>$l): ?><label><?= $l ?></label><input type="number" name="<?= $n ?>" class="form-control" value="0"><?php endforeach; ?></section><section class="col-12 panel"><h6>Estado entrega cable</h6><div class="row g-2"><div class="col-md-2"><select name="estado_operativo" class="form-select"><option>Operativo</option><option>No operativo</option><option>En observación</option><option>Dado de baja</option></select></div><div class="col-md-2"><input name="destino_cable" class="form-control" placeholder="Destino"></div><div class="col-md-2"><input name="tipo_enchufe_entrega" class="form-control" placeholder="Tipo enchufe"></div><div class="col-md-2"><input name="largo_entrega" class="form-control" placeholder="Largo entrega"></div><div class="col-md-2"><input name="marca_entrega" class="form-control" placeholder="Marca"></div><div class="col-md-2"><input name="capacidad_aislacion_entrega" class="form-control" placeholder="Capacidad aislación"></div></div></section><section class="col-md-6 panel"><h6>Falla Chaquetas/Mufas</h6><?php foreach($inf->fallasChaquetas as $o): ?><label class="check"><input type="checkbox" name="fallas_chaquetas[]" value="<?= e($o) ?>"> <?= e($o) ?></label><?php endforeach; ?></section><section class="col-md-6 panel"><h6>Falla Enchufe</h6><?php foreach($inf->fallasEnchufe as $o): ?><label class="check"><input type="checkbox" name="fallas_enchufe[]" value="<?= e($o) ?>"> <?= e($o) ?></label><?php endforeach; ?></section><?php foreach(['Prueba de continuidad'=>['Fase N° 1','Fase N° 2','Fase N° 3','Piloto'],'Prueba EZ-THUMP 12'=>['Fase N° 1','Fase N° 2','Fase N° 3','Piloto'],'Continuidad final'=>['Hilo piloto','Fase N° 1','Fase N° 2','Fase N° 3','Tierra'],'VLF'=>['Fase N° 1','Fase N° 2','Fase N° 3']] as $title=>$items): ?><section class="col-m